hooks.command:
NYBO_HOOK_ID=curate-on-edit NYBO_HOOK_TRUST=L1 bash -c 'nybo_trust=$(awk '\''/^level:/ {print $2}'\'' .nybo/trust.yaml 2>/dev/null)
case "$nybo_trust" in
  autonomous) : ;;
  semi-autonomous) case "$NYBO_HOOK_TRUST" in L1|L2) : ;; *) exit 0 ;; esac ;;
  supervised|"") case "$NYBO_HOOK_TRUST" in
    L1) if [ ! -t 0 ] || [ -n "$CLAUDE_CODE_HEADLESS" ]; then exit 0; fi
        printf "[nybo] hook %s — confirm? (y/N) " "$NYBO_HOOK_ID" >&2
        read -r _ans
        case "$_ans" in y|Y|yes|YES) : ;; *) exit 0 ;; esac ;;
    *) exit 0 ;;
  esac ;;
  *) exit 0 ;;
esac
file_path=$(printf '\''%s'\'' "$CLAUDE_TOOL_INPUT" | jq -r '\''.file_path // .filePath // empty'\'' 2>/dev/null)
case "$file_path" in *.nybo/*) printf '\''n\n'\'' | npx -y nybo curate >/dev/null 2>&1 || true ;; esac'
